#include <stdio.h>
#include <limits.h>

int main() {
    int T, N, i, j, k;
    static long long a[700][700];
    static long long dp[700][700];
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (i = 0; i < N; ++i) {
            for (j = 0; j < N; ++j) {
                scanf("%lld", &a[i][j]);
            }
        }
        for (j = 0; j < N; ++j) dp[0][j] = a[0][j];
        for (i = 1; i < N; ++i) {
            for (j = 0; j < N; ++j) {
                dp[i][j] = -1LL;
                for (k = 0; k < N; ++k) {
                    if (a[i][j] > a[i-1][k] && dp[i-1][k] != -1LL) {
                        long long cand = dp[i-1][k] + a[i][j];
                        if (cand > dp[i][j]) dp[i][j] = cand;
                    }
                }
            }
        }
        long long ans = -1LL;
        for (j = 0; j < N; ++j) if (dp[N-1][j] > ans) ans = dp[N-1][j];
        printf("%lld\n", ans);
    }
    return 0;
}

