import sys

def solve():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        a = [[int(next(it)) for _ in range(N)] for __ in range(N)]
        dp = [[-1]*N for _ in range(N)]
        for j in range(N):
            dp[0][j] = a[0][j]
        for i in range(1, N):
            for j in range(N):
                best = -1
                for k in range(N):
                    if a[i][j] > a[i-1][k] and dp[i-1][k] != -1:
                        cand = dp[i-1][k] + a[i][j]
                        if cand > best:
                            best = cand
                dp[i][j] = best
        ans = max(dp[N-1])
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

